/**
 * Updates persisted session preferences for the authenticated user.
 * @summary Update Session Preferences
 */
export const schemaVizSessionPartialUpdate = async (patchedSessionStateUpdateRequest?: PatchedSessionStateUpdateRequest, options?: RequestInit): Promise<schemaVizSessionPartialUpdateResponse> => {
    const formUrlEncoded = new URLSearchParams();
if(patchedSessionStateUpdateRequest?.locale !== undefined) {
 formUrlEncoded.append(`locale`, patchedSessionStateUpdateRequest.locale);
 }
if(patchedSessionStateUpdateRequest?.helpHintsEnabled !== undefined) {
 formUrlEncoded.append(`helpHintsEnabled`, patchedSessionStateUpdateRequest.helpHintsEnabled.toString())
 }
if(patchedSessionStateUpdateRequest?.helpHintsDismissed !== undefined) {
 formUrlEncoded.append(`helpHintsDismissed`, JSON.stringify(patchedSessionStateUpdateRequest.helpHintsDismissed));
 }
if(patchedSessionStateUpdateRequest?.aiApiKey !== undefined) {
 formUrlEncoded.append(`aiApiKey`, patchedSessionStateUpdateRequest.aiApiKey);
 }
if(patchedSessionStateUpdateRequest?.aiBaseUrl !== undefined) {
 formUrlEncoded.append(`aiBaseUrl`, patchedSessionStateUpdateRequest.aiBaseUrl);
 }
if(patchedSessionStateUpdateRequest?.aiModel !== undefined) {
 formUrlEncoded.append(`aiModel`, patchedSessionStateUpdateRequest.aiModel);
 }

  return schemaVizFetch<schemaVizSessionPartialUpdateResponse>(getSchemaVizSessionPartialUpdateUrl(),
  {
    ...options,
    method: 'PATCH',
    headers: { 'Content-Type': 'application/x-www-form-urlencoded', ...options?.headers },
    body: formUrlEncoded
  }
);}



